mapper.select:
SELECT answ.*, u.user_name, u.user_code, u.real_name
FROM t_apply_new_shares_order answ
         LEFT JOIN tz_user u ON answ.user_id = u.user_id
where 1 = 1


    and answ.order_no=#{orderNo}


    and answ.status=#{status}



    and answ.symbol_code  like  CONCAT('%', #{symbolCode}, '%')



    AND answ.user_id in

        #{item}




    and answ.symbol_name  like  CONCAT('%', #{symbolName}, '%')



    and u.user_name=#{userName} or u.user_code=#{userName}

 order by answ.create_time desc
